document.addEventListener("DOMContentLoaded",function(){const e=document.querySelector(".ebci2-contact-section"),t=document.querySelectorAll(".ebci2-contact-card");new IntersectionObserver((c,o)=>{c.forEach(c=>{c.isIntersecting&&(e.classList.add("show"),t.forEach((e,t)=>{setTimeout(()=>{e.classList.add("show")},1e3*t)}),o.unobserve(e))})},{threshold:.3}).observe(e)});